export type AdPlatform = 'google-ads' | 'meta-ads' | 'linkedin-ads';

export interface AdConnection {
  id: string;
  platform: AdPlatform;
  accountName: string;
  accountId: string;
  connectedAt: string;
  status: 'connected' | 'disconnected';
}

export interface RetargetingOpportunity {
  id: string;
  url: string;
  engine: string;
  query: string;
  estimatedAudience: number;
  pixelCode: string;
}

export interface BudgetEstimate {
  platform: AdPlatform;
  dailyBudget: number;
  estimatedReach: number;
  estimatedClicks: number;
  cpc: number;
  cpm: number;
}

import type {
  AdPlatform,
  AdConnection,
  RetargetingOpportunity,
  BudgetEstimate,
} from '../types/retargeting';

const STORAGE_KEY = 'citedby_ad_connections';

function randomId(): string {
  return Math.random().toString(36).substring(2, 10).toUpperCase();
}

function randomInRange(min: number, max: number): number {
  return Math.round((min + Math.random() * (max - min)) * 100) / 100;
}

export function getAdConnections(): AdConnection[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
}

function saveConnections(connections: AdConnection[]): void {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(connections));
}

const MOCK_ACCOUNTS: Record<AdPlatform, { names: string[]; prefix: string }> = {
  'google-ads': {
    names: ['Google Ads - Main', 'Google Ads - Brand', 'Google Ads - Performance'],
    prefix: 'GA',
  },
  'meta-ads': {
    names: ['Meta Business Suite', 'Meta Ads - Primary', 'Meta Ads - Retargeting'],
    prefix: 'MA',
  },
  'linkedin-ads': {
    names: ['LinkedIn Campaign Manager', 'LinkedIn Ads - B2B', 'LinkedIn Ads - Enterprise'],
    prefix: 'LA',
  },
};

export async function connectAdPlatform(platform: AdPlatform): Promise<AdConnection> {
  await new Promise((resolve) => setTimeout(resolve, 1500));

  const mock = MOCK_ACCOUNTS[platform];
  const name = mock.names[Math.floor(Math.random() * mock.names.length)];

  const connection: AdConnection = {
    id: `conn_${randomId()}`,
    platform,
    accountName: name,
    accountId: `${mock.prefix}-${Math.floor(100000000 + Math.random() * 900000000)}`,
    connectedAt: new Date().toISOString(),
    status: 'connected',
  };

  const connections = getAdConnections();
  connections.push(connection);
  saveConnections(connections);

  return connection;
}

export function disconnectAdPlatform(id: string): void {
  const connections = getAdConnections().map((conn) =>
    conn.id === id ? { ...conn, status: 'disconnected' as const } : conn
  );
  saveConnections(connections);
}

export function generateRetargetingOpportunities(
  citations: Array<{ url?: string; query: string; engine: string }>
): RetargetingOpportunity[] {
  return citations.map((citation) => {
    const pixelId = `CB-${randomId()}`;
    const url =
      citation.url ||
      `https://www.example.com/${citation.query.toLowerCase().replace(/\s+/g, '-')}`;
    const estimatedAudience = Math.floor(500 + Math.random() * 14500);

    const pixelCode = `<!-- CitedBy.ai Retargeting Pixel -->
<script>
  !function(c,b,r){c.cbq=c.cbq||[];var s=b.createElement('script');
  s.async=1;s.src='https://t.citedby.ai/pixel.js';
  b.head.appendChild(s)}(window,document);
  cbq('init','${pixelId}');
  cbq('track','AIVisitor',{source:'${citation.engine}',query:'${citation.query.replace(/'/g, "\\'")}'});
</script>`;

    return {
      id: `opp_${randomId()}`,
      url,
      engine: citation.engine,
      query: citation.query,
      estimatedAudience,
      pixelCode,
    };
  });
}

const PLATFORM_RATES: Record<AdPlatform, { cpc: [number, number]; cpm: [number, number] }> = {
  'google-ads': { cpc: [0.35, 0.85], cpm: [3.5, 8.0] },
  'meta-ads': { cpc: [0.25, 0.65], cpm: [5.0, 12.0] },
  'linkedin-ads': { cpc: [1.5, 4.5], cpm: [15.0, 35.0] },
};

export function estimateBudget(
  platform: AdPlatform,
  dailyBudget: number,
  audienceSize: number
): BudgetEstimate {
  const rates = PLATFORM_RATES[platform];
  const cpc = randomInRange(rates.cpc[0], rates.cpc[1]);
  const cpm = randomInRange(rates.cpm[0], rates.cpm[1]);

  const estimatedReach = Math.round(dailyBudget / (cpm / 1000));
  const estimatedClicks = Math.round(dailyBudget / cpc);

  return {
    platform,
    dailyBudget,
    estimatedReach,
    estimatedClicks,
    cpc,
    cpm,
  };
}

export function exportAudienceCSV(opportunities: RetargetingOpportunity[]): string {
  const headers = 'URL,Engine,Query,Estimated Audience,Pixel ID';
  const rows = opportunities.map((opp) => {
    const pixelIdMatch = opp.pixelCode.match(/cbq\('init','(CB-[A-Z0-9]+)'\)/);
    const pixelId = pixelIdMatch ? pixelIdMatch[1] : '';
    const escapedQuery = `"${opp.query.replace(/"/g, '""')}"`;
    return `${opp.url},${opp.engine},${escapedQuery},${opp.estimatedAudience},${pixelId}`;
  });

  return [headers, ...rows].join('\n');
}

export function downloadCSV(csv: string, filename: string): void {
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.setAttribute('download', filename);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
}
